import { COLLEGES, getCollegeBySlug } from "@/lib/colleges";
import { AP_CUTOFFS, AP_CUTOFF_YEARS, CollegeCutoffs } from "@/lib/ap-cutoffs";
import { notFound } from "next/navigation";
import CollegeDetail from "./CollegeDetail";

export function generateStaticParams() {
  return COLLEGES.map(c => ({ slug: c.slug }));
}

export async function generateMetadata({ params }: { params: Promise<{ slug: string }> }) {
  const { slug } = await params;
  const c = getCollegeBySlug(slug);
  if (!c) return {};
  return {
    title: `${c.name} — Fee, Cutoffs, Placements | TeluguColleges`,
    description: `${c.name} (${c.code}) in ${c.district}, ${c.state}. B.Tech fee, EAPCET cutoff ranks, placements, NAAC & NIRF rankings.`,
  };
}

export default async function CollegePage({ params }: { params: Promise<{ slug: string }> }) {
  const { slug } = await params;
  const c = getCollegeBySlug(slug);
  if (!c) notFound();

  const similar = COLLEGES.filter(s => s.id !== c.id && s.state === c.state && s.cutoff.cse > 0 && c.cutoff.cse > 0 && Math.abs(s.cutoff.cse - c.cutoff.cse) < 5000).slice(0, 4);
  const historicalCutoffs = AP_CUTOFFS[c.code] || null;
  const cutoffYears = AP_CUTOFF_YEARS;

  return <CollegeDetail c={c} similar={similar} historicalCutoffs={historicalCutoffs} cutoffYears={cutoffYears} />;
}
